function Gauge({ value = 0, min = 0, max = 100, label = '', unit = '' }) {
  const pct = Math.min(100, Math.max(0, ((value - min) / (max - min)) * 100));
  const color = pct > 80 ? 'text-red-400' : pct > 50 ? 'text-amber-400' : 'text-green-400';
  const bg = pct > 80 ? 'from-red-500' : pct > 50 ? 'from-amber-500' : 'from-green-500';
  return (
    <div className="flex flex-col items-center p-4">
      <div className="text-xs text-zinc-500 uppercase tracking-wider mb-2">{label}</div>
      <div className="relative w-28 h-28 rounded-full bg-zinc-900 flex items-center justify-center">
        <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
          <circle cx="50" cy="50" r="42" fill="none" strokeWidth="6" className="stroke-zinc-800" />
          <circle cx="50" cy="50" r="42" fill="none" strokeWidth="6"
            className={`stroke-current ${color}`}
            strokeDasharray={`${pct * 2.64} 264`}
            strokeLinecap="round" />
        </svg>
        <div className={`text-2xl font-bold ${color}`}>
          {Math.round(value)}<span className="text-sm ml-0.5">{unit}</span>
        </div>
      </div>
    </div>
  );
}

function Button({ onClick, children, variant = 'primary', className = '' }) {
  const base = 'px-4 py-2 rounded-lg font-medium transition-colors';
  const variants = {
    primary: 'bg-blue-600 text-white hover:bg-blue-500',
    secondary: 'bg-zinc-700 text-zinc-200 hover:bg-zinc-600',
    danger: 'bg-red-600 text-white hover:bg-red-500'
  };
  return (
    <button
      className={`${base} ${variants[variant] || variants.primary} ${className}`}
      onClick={onClick}
    >{children}</button>
  );
}

function ValueBadge({ label, value, className = '' }) {
  if (value == null) return null;
  return (
    <span className={`text-zinc-600 text-xs ${className}`}>
      {label && <>{label}: </>}{value}
    </span>
  );
}

